B.Tg=A.b(s(["Flutter","REST APIs","Firebase","Paymob","Local Auth","In-App Purchases"]),t.s)
B.WB=new A.bJ(B.f2,["fintech","Frenn Microfinance App","A production-grade microfinance and mobile banking hub designed to deliver secure, real-time financial services. Features high-grade biometric authentication (FaceID/TouchID), instant cash graphical wallets, and integration with Stripe for transaction processing. The app enables comprehensive Buy Now Pay Later (BNPL) options, mobile airtime recharges, and real-time transaction tracking with PDF receipt generation, all built on a robust caching repository architecture.",!1,B.Ta,B.Tg],t.yf)
B.SE=A.b(s(["In-App Purchases (IAP) integration via Google Play Billing & Apple StoreKit for premium tier subscriptions","Membership ecosystem featuring paywalled premium feeds, gated connection requests, and exclusive job postings","User-created custom business, company, and educational institution organization pages","Real-time direct and group chatting with WebSockets and dynamic typing status indicators","Infinite scrolling paginated content feed with smart client-side media caching","Robust Node.js backend API architecture managing real-time feed curation, comments, and security states"]),t.s)
B.Ud=A.b(s(["Flutter","Node.js","WebSockets","Express","MongoDB"]),t.s)
B.Ww=new A.bJ(B.f2,["nobelpage","Nobelpage","A production-grade, highly engaging professional networking and social media ecosystem reminiscent of LinkedIn. Designed with a robust Node.js backend and modular Flutter architecture, Nobelpage empowers users to build professional networks, create dedicated organization pages for institutions and companies, and access exclusive premium tiers. The ecosystem is fully equipped with secure App Store and Play Store in-app purchases (IAP) for subscriptions, membership paywalls, gated content access, and real-time WebSocket communication.",!1,B.SE,B.Ud],t.yf)
B.Ub=A.b(s(["Real-time table booking calendar and reservation coordinator","Live order dispatch tracking and kitchen receipt queuing","Dynamic digital menus with remote configuration options","Aggregated review analysis and statistics dashboard","Multi-vendor payments setup"]),t.s)
B.Un=A.b(s(["Flutter","SQL database","Push Notification"]),t.s)
B.Wy=new A.bJ(B.f2,["restaurant","Restridvisor - Restaurant Management App","A feature-rich, dual-sided restaurant booking and live order management ecosystem designed to coordinate customer-to-merchant operations. Equipped with a real-time reservation coordinator calendar, interactive digital menu configurations, and multi-vendor checkout setups. Merchants benefit from instant kitchen order ticket queue tracking and analytics dashboards, while customers enjoy live dispatch updates and reviews submission flows.",!1,B.Ub,B.Un],t.yf)
B.RZ=A.b(s(["Time slot reservation matrix with calendar integration","Dynamic category-based service browsing and booking workflow","Interactive service provider dashboard for tracking schedules and payouts","Stripe-powered checkout with digital invoices"]),t.s)
